package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.function.Executable;
import org.mockito.Mockito;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Constructor;

class CSVFormatTest {

    @Test
    void testFormatWithNormalValues() throws IOException {
        CSVFormat format = CSVFormat.DEFAULT;
        String result = format.format("a", "b", "c");
        // The output should be CSV record with comma delimiter and CRLF line ending trimmed
        assertEquals("a,b,c", result);
    }

    @Test
    void testFormatWithNullValue() {
        CSVFormat format = CSVFormat.DEFAULT.withNullString("NULL");
        String result = format.format("a", null, "c");
        assertEquals("a,NULL,c", result);
    }

    @Test
    void testFormatWithEmptyValues() {
        CSVFormat format = CSVFormat.DEFAULT;
        String result = format.format();
        // Empty record should produce empty string after trim
        assertEquals("", result);
    }

    @Test
    void testFormatWithIOException() throws Exception {
        CSVFormat format = Mockito.spy(CSVFormat.DEFAULT);

        // Use reflection to mock CSVPrinter constructor to throw IOException
        Constructor<CSVPrinter> constructor = CSVPrinter.class.getConstructor(Appendable.class, CSVFormat.class);

        CSVPrinter csvPrinterProxy = Mockito.mock(CSVPrinter.class);

        // Mock the constructor to throw IOException when called with StringWriter and format
        ConstructorInvocationMocker.mockConstructorThrowing(constructor, new IOException("forced IO exception"));

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> format.format("a"));
        assertTrue(thrown.getCause() instanceof IOException);
        assertEquals("forced IO exception", thrown.getCause().getMessage());

        // Clear the constructor mock after test
        ConstructorInvocationMocker.clearMock(constructor);
    }

    @Test
    void testFormatWithDifferentFormats() {
        CSVFormat[] formats = new CSVFormat[] {
                CSVFormat.EXCEL,
                CSVFormat.INFORMIX_UNLOAD,
                CSVFormat.INFORMIX_UNLOAD_CSV,
                CSVFormat.MYSQL,
                CSVFormat.POSTGRESQL_CSV,
                CSVFormat.POSTGRESQL_TEXT,
                CSVFormat.RFC4180,
                CSVFormat.TDF
        };

        for (CSVFormat format : formats) {
            String result = format.format("x", "y", "z");
            assertNotNull(result);
            assertFalse(result.isEmpty());
            // Basic check that output contains the first value
            assertTrue(result.contains("x"));
        }
    }
}

/**
 * Utility class to mock constructor invocation to throw exception.
 * This uses a custom SecurityManager to intercept constructor calls.
 */
class ConstructorInvocationMocker {
    private static volatile Constructor<?> mockedConstructor;
    private static volatile RuntimeException toThrow;

    public static <T> void mockConstructorThrowing(Constructor<T> constructor, IOException exception) {
        mockedConstructor = constructor;
        toThrow = new RuntimeException(exception);

        // Set a custom SecurityManager to intercept newInstance calls
        System.setSecurityManager(new SecurityManager() {
            @Override
            public void checkPermission(java.security.Permission perm) {
                // allow everything
            }

            @Override
            public void checkMemberAccess(Class<?> clazz, int which) {
                if (mockedConstructor != null && clazz == mockedConstructor.getDeclaringClass()) {
                    throw toThrow;
                }
            }
        });
    }

    public static void clearMock(Constructor<?> constructor) {
        if (mockedConstructor == constructor) {
            mockedConstructor = null;
            toThrow = null;
            System.setSecurityManager(null);
        }
    }
}
